void preset_apply(DX_Synth_Bridge* dx)
{
    dx->patch() = dx_patch_stage();
}

static uint8_t s_current = 0;

void preset_stage(uint8_t idx)
{
    if (idx >= DX_NPRESETS) return;
    dx_patch_stage() = dxPresets[idx].patch;
    ipc_send_dx_patch_apply();
}

void preset_set_current(uint8_t idx)
{
    s_current = idx;
}

uint8_t preset_get_current(void)
{
    return s_current;
}
